#include<bits/stdc++.h>
using namespace std;
int main(){
    int n,m,ans=0,s=0;
    cin>>n>>m;
    for(int i=1;i<=n;i++){
        int x;
        cin>>x;
        if(s<m){
            ans+=(x/2);
            s+=x;
        }else{
            ans+=(x*2);
            s/=2;
        }
    }
    cout<<ans;
    return 0;
}
